const items = $input.all();

let answer = "";
let suggestions = [];
let tongHeThong = 0;

for (const item of items) {
  const d = item.json;

  if (d.ma_donvi !== undefined && d.ma_donvi !== null) {

    let tenDonVi = d.ten_donvi;
    let isDonViChung = false;

    if (tenDonVi === "Default organization") {
      tenDonVi = "Đơn vị chung";
      isDonViChung = true;
    }

    answer += `- **Đơn vị**: ${tenDonVi}\n`;
    answer += `+ Số thiết bị là: ${d.tong_thiet_bi}\n\n`;

    // chỉ tạo suggestion nếu KHÔNG phải đơn vị chung
    if (!isDonViChung) {
      if (d.ma_donvi) {
        suggestions.push(`Thống kê tổng quan thiết bị của đơn vị ${d.ma_donvi}`);
      }
    }
  }

  if (d.tong_thiet_bi_toan_he_thong !== undefined) {
    tongHeThong = d.tong_thiet_bi_toan_he_thong;
  }
}

answer += `**Tổng số thiết bị của toàn hệ thống là:** ${tongHeThong}`;

return [
  {
    json: {
      answer: answer.trim(),
      suggestions: suggestions
    }
  }
];

const items = $input.all();

let answer = "";
let suggestions = [];

let tongQuan = null;
let loaiThietBi = [];

for (const item of items) {
  const d = item.json;

  // record tổng quan đơn vị
  if (d.ma_donvi) {
    tongQuan = d;
  }

  // record loại thiết bị
  if (d.ten_loai_thiet_bi) {
    loaiThietBi.push(d.ten_loai_thiet_bi);
  }
}

if (tongQuan) {
  answer += `- **Đơn vị:** ${tongQuan.ten_donvi}\n\n`;
  answer += `+ Số loại thiết bị: ${tongQuan.so_loai_thiet_bi}\n`;
  answer += `+ Số bộ phận: ${tongQuan.so_bo_phan}\n`;
  answer += `+ Số thiết bị hoạt động: ${tongQuan.so_thiet_bi_hoat_dong}\n`;
  answer += `+ Số thiết bị chờ gỡ bỏ: ${tongQuan.so_thiet_bi_cho_go_bo}\n`;
  answer += `+ Số thiết bị đã gỡ bỏ: ${tongQuan.so_thiet_bi_da_go_bo}\n\n`;

  answer += `Tổng số thiết bị của toàn đơn vị là: ${tongQuan.tong_thiet_bi}\n\n`;
}

answer += `- **Dưới đây là 1 số loại thiết bị:**\n\n`;

for (const ten of loaiThietBi) {
  answer += `+ ${ten}\n`;

  if (suggestions.length < 3) {
    suggestions.push(`Xem danh sách thiết bị thuộc loại ${ten}`);
  }
}

answer += `\n- **Xem chi tiết**: https://cmms.vimico.vn/asset`;

return [
  {
    json: {
      answer: answer.trim(),
      suggestions: suggestions
    }
  }
];

const items = $input.all();

let answer = "";
let suggestions = [];

let tongSoThietBi = 0;
let tenLoaiThietBi = "";
let devices = [];

for (const item of items) {
  const d = item.json;

  // record tổng số
  if (d.tong_so_thiet_bi !== undefined) {
    tongSoThietBi = d.tong_so_thiet_bi;
  }

  // record thiết bị
  if (d.ma_thiet_bi) {
    devices.push(d);
    tenLoaiThietBi = d.ten_loai_thiet_bi;
  }
}

// in danh sách thiết bị
for (const dev of devices) {
  answer += `- **Tên thiết bị:** ${dev.ten_thiet_bi}\n\n`;
  answer += `+ Mã thiết bị: ${dev.ma_thiet_bi}\n`;
  answer += `+ Bộ phận: ${dev.ten_bo_phan}\n`;
  answer += `+ Trạng thái: ${dev.ten_trang_thai}\n\n`;

  // tạo suggestion từ mã thiết bị
  if (suggestions.length < 4) {
    suggestions.push(`Chi tiết thiết bị ${dev.ma_thiet_bi}`);
    suggestions.push(`Lịch sử hoạt động của thiết bị ${dev.ma_thiet_bi}`);
    suggestions.push(`Lịch sử sửa chữa của thiết bị ${dev.ma_thiet_bi}`);
  }
}

// tổng số
answer += `- **Tổng số thiết bị thuộc loại ${tenLoaiThietBi}:** ${tongSoThietBi}.\n\n`;

answer += `- **Xem chi tiết**: https://cmms.vimico.vn/asset`;

return [
  {
    json: {
      answer: answer.trim(),
      suggestions: suggestions.slice(0,4)
    }
  }
];

